from typing import List

class TweetCounts:

    def __init__(self):
        self.tweets = {}

    def recordTweet(self, tweetName: str, time: int) -> None:
        if tweetName not in self.tweets:
            self.tweets[tweetName] = []
        self.tweets[tweetName].append(time)

    def getTweetCountsPerFrequency(self, freq: str, tweetName: str, startTime: int, endTime: int) -> List[int]:
        if tweetName not in self.tweets:
            return []

        time_chunks = self.getTimeChunks(freq, startTime, endTime)
        tweet_counts = [0] * len(time_chunks)

        for time in self.tweets[tweetName]:
            for i, (start, end) in enumerate(time_chunks):
                if start <= time <= end:
                    tweet_counts[i] += 1

        return tweet_counts

    def getTimeChunks(self, freq: str, startTime: int, endTime: int):
        if freq == "minute":
            chunk_size = 60
        elif freq == "hour":
            chunk_size = 3600
        elif freq == "day":
            chunk_size = 86400
        else:
            raise ValueError("Invalid frequency")

        time_chunks = []
        current_time = startTime
        while current_time <= endTime:
            time_chunks.append((current_time, min(current_time + chunk_size - 1, endTime)))
            current_time += chunk_size

        return time_chunks
```

efficiency: HIGH
time complexity: O(n + m), where n is the number of tweets and m is the number of time chunks
space complexity: O(n), where n is the number of tweets
